@* 
    Interactive component embedded in the static layout.
    Because it runs with @rendermode InteractiveServer, it shares the same
    circuit (and scoped WizardState) as the wizard page components.
*@
@using sv_da840e0fc06e4b52a8660c31979f9a2c.Services
@inject WizardState WizardState
@inject NavigationManager Navigation
@implements IDisposable

@{
    var currentStep = GetCurrentStep();
}

@if (currentStep > 0)
{
    <nav class="wizard-progress px-4 py-3 border-bottom bg-light" aria-label="Application progress">
        <div class="d-flex justify-content-between align-items-center mb-2">
            <h6 class="mb-0">Job Application</h6>
            <span class="badge bg-primary rounded-pill">Step @currentStep of @Steps.Length</span>
        </div>
        <div class="d-flex gap-1">
            @for (var i = 0; i < Steps.Length; i++)
            {
                var stepNum = i + 1;
                var isCurrent = stepNum == currentStep;
                var isCompleted = WizardState.CompletedSteps.Contains(stepNum);
                var css = isCurrent ? "btn-primary"
                        : isCompleted ? "btn-success"
                        : "btn-outline-secondary";

                <a href="@Steps[i].Url"
                   class="btn @css btn-sm flex-fill"
                   aria-current="@(isCurrent ? "step" : null)">
                    @stepNum. @Steps[i].Label
                </a>
            }
        </div>
    </nav>
}

@code {
    private static readonly (string Url, string Label)[] Steps =
    [
        ("/apply/personal-info", "Personal Info"),
        ("/apply/experience", "Experience"),
        ("/apply/references", "References"),
        ("/apply/review", "Review")
    ];

    private Action? _stateHandler;

    protected override void OnInitialized()
    {
        _stateHandler = () => InvokeAsync(StateHasChanged);
        Navigation.LocationChanged += OnLocationChanged;
        WizardState.OnChange += _stateHandler;
    }

    private int GetCurrentStep()
    {
        var path = new Uri(Navigation.Uri).AbsolutePath;
        for (var i = 0; i < Steps.Length; i++)
        {
            if (path.Equals(Steps[i].Url, StringComparison.OrdinalIgnoreCase))
                return i + 1;
        }
        return 0;
    }

    private void OnLocationChanged(object? sender, LocationChangedEventArgs e)
        => InvokeAsync(StateHasChanged);

    public void Dispose()
    {
        Navigation.LocationChanged -= OnLocationChanged;
        if (_stateHandler is not null)
            WizardState.OnChange -= _stateHandler;
    }
}

