@page "/apply/personal-info"
@rendermode InteractiveServer
@using sv_da840e0fc06e4b52a8660c31979f9a2c.Services
@inject WizardState WizardState
@inject NavigationManager Navigation

<PageTitle>Personal Info – Job Application</PageTitle>

<h3>Personal Information</h3>

<div class="mb-3">
    <label class="form-label">Full Name</label>
    <input class="form-control" @bind="WizardState.PersonalInfo.Name" />
</div>

<div class="mb-3">
    <label class="form-label">Email Address</label>
    <input type="email" class="form-control" @bind="WizardState.PersonalInfo.Email" />
</div>

<div class="d-flex justify-content-end">
    <button class="btn btn-primary" @onclick="Next">Next &rarr;</button>
</div>

@code {
    private void Next()
    {
        WizardState.CompleteStep(1);
        Navigation.NavigateTo("/apply/experience");
    }
}

@page "/apply/experience"
@rendermode InteractiveServer
@using sv_da840e0fc06e4b52a8660c31979f9a2c.Models
@using sv_da840e0fc06e4b52a8660c31979f9a2c.Services
@inject WizardState WizardState
@inject NavigationManager Navigation

<PageTitle>Experience – Job Application</PageTitle>

<h3>Work Experience</h3>

@if (WizardState.Experience.Count == 0)
{
    <p class="text-muted">No entries yet. Add your work experience below.</p>
}

@for (var i = 0; i < WizardState.Experience.Count; i++)
{
    var entry = WizardState.Experience[i];
    var index = i;

    <div class="card mb-3">
        <div class="card-body">
            <div class="d-flex justify-content-between align-items-center mb-2">
                <h6 class="mb-0">Entry @(index + 1)</h6>
                <button class="btn btn-sm btn-outline-danger" @onclick="() => Remove(index)">Remove</button>
            </div>
            <div class="mb-2">
                <label class="form-label">Company</label>
                <input class="form-control" @bind="entry.Company" />
            </div>
            <div class="mb-2">
                <label class="form-label">Job Title</label>
                <input class="form-control" @bind="entry.Title" />
            </div>
            <div class="mb-2">
                <label class="form-label">Duration</label>
                <input class="form-control" @bind="entry.Duration" placeholder="e.g., Jan 2020 – Dec 2022" />
            </div>
        </div>
    </div>
}

<button class="btn btn-outline-primary mb-3" @onclick="Add">+ Add Experience</button>

<div class="d-flex justify-content-between">
    <button class="btn btn-secondary" @onclick="Back">&larr; Back</button>
    <button class="btn btn-primary" @onclick="Next">Next &rarr;</button>
</div>

@code {
    private void Add() => WizardState.Experience.Add(new ExperienceEntry());
    private void Remove(int index) => WizardState.Experience.RemoveAt(index);
    private void Back() => Navigation.NavigateTo("/apply/personal-info");

    private void Next()
    {
        WizardState.CompleteStep(2);
        Navigation.NavigateTo("/apply/references");
    }
}

@page "/apply/references"
@rendermode InteractiveServer
@using sv_da840e0fc06e4b52a8660c31979f9a2c.Models
@using sv_da840e0fc06e4b52a8660c31979f9a2c.Services
@inject WizardState WizardState
@inject NavigationManager Navigation

<PageTitle>References – Job Application</PageTitle>

<h3>References</h3>

@if (WizardState.References.Count == 0)
{
    <p class="text-muted">No references yet. Add your reference contacts below.</p>
}

@for (var i = 0; i < WizardState.References.Count; i++)
{
    var contact = WizardState.References[i];
    var index = i;

    <div class="card mb-3">
        <div class="card-body">
            <div class="d-flex justify-content-between align-items-center mb-2">
                <h6 class="mb-0">Reference @(index + 1)</h6>
                <button class="btn btn-sm btn-outline-danger" @onclick="() => Remove(index)">Remove</button>
            </div>
            <div class="mb-2">
                <label class="form-label">Name</label>
                <input class="form-control" @bind="contact.Name" />
            </div>
            <div class="mb-2">
                <label class="form-label">Email</label>
                <input type="email" class="form-control" @bind="contact.Email" />
            </div>
            <div class="mb-2">
                <label class="form-label">Relationship</label>
                <input class="form-control" @bind="contact.Relationship" placeholder="e.g., Former Manager" />
            </div>
        </div>
    </div>
}

<button class="btn btn-outline-primary mb-3" @onclick="Add">+ Add Reference</button>

<div class="d-flex justify-content-between">
    <button class="btn btn-secondary" @onclick="Back">&larr; Back</button>
    <button class="btn btn-primary" @onclick="Next">Next &rarr;</button>
</div>

@code {
    private void Add() => WizardState.References.Add(new ReferenceContact());
    private void Remove(int index) => WizardState.References.RemoveAt(index);
    private void Back() => Navigation.NavigateTo("/apply/experience");

    private void Next()
    {
        WizardState.CompleteStep(3);
        Navigation.NavigateTo("/apply/review");
    }
}

@page "/apply/review"
@rendermode InteractiveServer
@using sv_da840e0fc06e4b52a8660c31979f9a2c.Services
@inject WizardState WizardState
@inject NavigationManager Navigation

<PageTitle>Review – Job Application</PageTitle>

<h3>Review Your Application</h3>

<div class="card mb-3">
    <div class="card-header d-flex justify-content-between align-items-center">
        <strong>Personal Information</strong>
        <a href="/apply/personal-info" class="btn btn-sm btn-outline-primary">Edit</a>
    </div>
    <div class="card-body">
        <dl class="row mb-0">
            <dt class="col-sm-3">Name</dt>
            <dd class="col-sm-9">@NoneIfEmpty(WizardState.PersonalInfo.Name)</dd>
            <dt class="col-sm-3">Email</dt>
            <dd class="col-sm-9">@NoneIfEmpty(WizardState.PersonalInfo.Email)</dd>
        </dl>
    </div>
</div>

<div class="card mb-3">
    <div class="card-header d-flex justify-content-between align-items-center">
        <strong>Work Experience</strong>
        <a href="/apply/experience" class="btn btn-sm btn-outline-primary">Edit</a>
    </div>
    <div class="card-body">
        @if (WizardState.Experience.Count == 0)
        {
            <p class="text-muted mb-0">No experience entries.</p>
        }
        else
        {
            @foreach (var entry in WizardState.Experience)
            {
                <div class="mb-2">
                    <strong>@entry.Title</strong> at @entry.Company
                    <br />
                    <small class="text-muted">@entry.Duration</small>
                </div>
            }
        }
    </div>
</div>

<div class="card mb-3">
    <div class="card-header d-flex justify-content-between align-items-center">
        <strong>References</strong>
        <a href="/apply/references" class="btn btn-sm btn-outline-primary">Edit</a>
    </div>
    <div class="card-body">
        @if (WizardState.References.Count == 0)
        {
            <p class="text-muted mb-0">No references.</p>
        }
        else
        {
            @foreach (var contact in WizardState.References)
            {
                <div class="mb-2">
                    <strong>@contact.Name</strong> – @contact.Relationship
                    <br />
                    <small class="text-muted">@contact.Email</small>
                </div>
            }
        }
    </div>
</div>

<div class="d-flex justify-content-between">
    <button class="btn btn-secondary" @onclick="Back">&larr; Back</button>
    <button class="btn btn-success" @onclick="Submit">Submit Application</button>
</div>

@if (_submitted)
{
    <div class="alert alert-success mt-3" role="alert">
        Your application has been submitted successfully!
    </div>
}

@code {
    private bool _submitted;

    private void Back() => Navigation.NavigateTo("/apply/references");

    private void Submit()
    {
        WizardState.CompleteStep(4);
        _submitted = true;
    }

    private static string NoneIfEmpty(string value)
        => string.IsNullOrWhiteSpace(value) ? "–" : value;
}

